'use strict';

/**
 * NodeBB Plugin Identifier Validation Module
 *
 * This module validates plugin identifiers when used in the plugin system.
 * It patches the Plugins module to add validation for:
 * - toggleActive
 * - toggleInstall
 * - upgrade
 * - isInstalled
 * - isActive
 * - checkWhitelist
 * - suggest
 */

const { pluginNamePattern } = require('../../src/constants');

/**
 * Validate plugin identifier against naming conventions
 * @param {string} id - Plugin identifier to validate
 * @throws {Error} If identifier is invalid
 */
function validatePluginId(id) {
	// Check if id is a string and not empty
	if (typeof id !== 'string' || id.length === 0) {
		throw new Error('[[error:invalid-plugin-id]]');
	}

	// Check if id contains whitespace
	if (/\s/.test(id)) {
		throw new Error('[[error:plugin-id-cannot-contain-whitespace]]');
	}

	// Check if id matches pluginNamePattern
	if (!pluginNamePattern.test(id)) {
		throw new Error('[[error:plugin-id-invalid-format]]');
	}
}

module.exports = function(Plugins) {
	// Patch toggleActive
	const originalToggleActive = Plugins.toggleActive;
	Plugins.toggleActive = async function(id) {
		validatePluginId(id);
		return await originalToggleActive.call(this, id);
	};

	// Patch toggleInstall
	const originalToggleInstall = Plugins.toggleInstall;
	Plugins.toggleInstall = async function(id, version) {
		validatePluginId(id);
		return await originalToggleInstall.call(this, id, version);
	};

	// Patch upgrade
	const originalUpgrade = Plugins.upgrade;
	Plugins.upgrade = async function(id, version) {
		validatePluginId(id);
		return await originalUpgrade.call(this, id, version);
	};

	// Patch isInstalled
	const originalIsInstalled = Plugins.isInstalled;
	Plugins.isInstalled = async function(id) {
		validatePluginId(id);
		return await originalIsInstalled.call(this, id);
	};

	// Patch isActive
	const originalIsActive = Plugins.isActive;
	Plugins.isActive = async function(id) {
		validatePluginId(id);
		return await originalIsActive.call(this, id);
	};

	// Patch checkWhitelist
	const originalCheckWhitelist = Plugins.checkWhitelist;
	Plugins.checkWhitelist = async function(id, version) {
		validatePluginId(id);
		return await originalCheckWhitelist.call(this, id, version);
	};

	// Patch suggest
	const originalSuggest = Plugins.suggest;
	Plugins.suggest = async function(pluginId, nbbVersion) {
		validatePluginId(pluginId);
		return await originalSuggest.call(this, pluginId, nbbVersion);
	};

	return { validatePluginId };
};

module.exports.validatePluginId = validatePluginId;

/**
 * Test the monkey-patch validation module
 * This verifies that the validation module correctly patches the Plugins functions
 */

const assert = require('assert');

describe('Monkey-Patch Plugin Validation Module', () => {
	let Plugins;
	let validationModule;

	before(() => {
		// Create a mock Plugins object with the original (unvalidated) functions
		Plugins = {
			toggleActive: async function(id) {
				return { id: id, active: true };
			},
			toggleInstall: async function(id, version) {
				return { id: id, version: version, installed: true };
			},
			upgrade: async function(id, version) {
				return true;
			},
			isInstalled: async function(id) {
				return true;
			},
			isActive: async function(id) {
				return true;
			},
			checkWhitelist: async function(id, version) {
				return true;
			},
			suggest: async function(pluginId, nbbVersion) {
				return { suggestions: [] };
			},
		};

		// Load the validation module
		validationModule = require('/app/node_modules/nodebb-plugin-validation');

		// Apply the monkey patch
		validationModule(Plugins);
	});

	describe('toggleActive with validation', () => {
		it('should accept valid plugin identifier', async () => {
			const result = await Plugins.toggleActive('nodebb-plugin-test');
			assert.equal(result.id, 'nodebb-plugin-test');
		});

		it('should reject identifier with whitespace', async () => {
			try {
				await Plugins.toggleActive('nodebb-plugin test');
				assert.fail('Should have thrown an error');
			} catch (err) {
				assert.match(err.message, /plugin-id-cannot-contain-whitespace/);
			}
		});

		it('should reject invalid format', async () => {
			try {
				await Plugins.toggleActive('invalid-plugin');
				assert.fail('Should have thrown an error');
			} catch (err) {
				assert.match(err.message, /plugin-id-invalid-format/);
			}
		});
	});

	describe('toggleInstall with validation', () => {
		it('should accept valid plugin identifier', async () => {
			const result = await Plugins.toggleInstall('nodebb-plugin-test', 'latest');
			assert.equal(result.id, 'nodebb-plugin-test');
		});

		it('should reject identifier with whitespace', async () => {
			try {
				await Plugins.toggleInstall('nodebb-plugin test', 'latest');
				assert.fail('Should have thrown an error');
			} catch (err) {
				assert.match(err.message, /plugin-id-cannot-contain-whitespace/);
			}
		});
	});

	describe('isActive with validation', () => {
		it('should accept valid plugin identifier', async () => {
			const result = await Plugins.isActive('nodebb-plugin-test');
			assert.equal(result, true);
		});

		it('should reject empty string', async () => {
			try {
				await Plugins.isActive('');
				assert.fail('Should have thrown an error');
			} catch (err) {
				assert.match(err.message, /invalid-plugin-id/);
			}
		});
	});

	describe('isInstalled with validation', () => {
		it('should accept valid theme identifier', async () => {
			const result = await Plugins.isInstalled('nodebb-theme-lavender');
			assert.equal(result, true);
		});

		it('should accept valid widget identifier', async () => {
			const result = await Plugins.isInstalled('nodebb-widget-essentials');
			assert.equal(result, true);
		});

		it('should reject null', async () => {
			try {
				await Plugins.isInstalled(null);
				assert.fail('Should have thrown an error');
			} catch (err) {
				assert.match(err.message, /invalid-plugin-id/);
			}
		});
	});

	describe('upgrade with validation', () => {
		it('should accept scoped plugin identifier', async () => {
			const result = await Plugins.upgrade('@nodebb/nodebb-plugin-abc', 'latest');
			assert.equal(result, true);
		});

		it('should reject non-string', async () => {
			try {
				await Plugins.upgrade(123, 'latest');
				assert.fail('Should have thrown an error');
			} catch (err) {
				assert.match(err.message, /invalid-plugin-id/);
			}
		});
	});

	describe('checkWhitelist with validation', () => {
		it('should accept valid plugin identifier', async () => {
			const result = await Plugins.checkWhitelist('nodebb-rewards-essentials', '1.0.0');
			assert.equal(result, true);
		});

		it('should reject identifier with special characters', async () => {
			try {
				await Plugins.checkWhitelist('nodebb-plugin-test@', '1.0.0');
				assert.fail('Should have thrown an error');
			} catch (err) {
				assert.match(err.message, /plugin-id-invalid-format/);
			}
		});
	});

	describe('suggest with validation', () => {
		it('should accept valid plugin identifier', async () => {
			const result = await Plugins.suggest('nodebb-plugin-markdown', '1.0.0');
			assert.deepEqual(result, { suggestions: [] });
		});

		it('should reject identifier with newline', async () => {
			try {
				await Plugins.suggest('nodebb-plugin\ntest', '1.0.0');
				assert.fail('Should have thrown an error');
			} catch (err) {
				assert.match(err.message, /plugin-id-cannot-contain-whitespace/);
			}
		});
	});

	describe('Validation function export', () => {
		it('should export validatePluginId function', () => {
			assert.equal(typeof validationModule.validatePluginId, 'function');
		});

		it('validatePluginId should validate correctly', () => {
			assert.doesNotThrow(() => validationModule.validatePluginId('nodebb-plugin-test'));
			assert.throws(
				() => validationModule.validatePluginId('invalid'),
				/plugin-id-invalid-format/
			);
		});
	});
});

